import "container/heap"

type MinHeap struct {
	elements []int64
}

func (h *MinHeap) Len() int {
	return len(h.elements)
}

func (h *MinHeap) Less(i, j int) bool {
	return h.elements[i] < h.elements[j]
}

func (h *MinHeap) Swap(i, j int) {
	h.elements[i], h.elements[j] = h.elements[j], h.elements[i]
}

func (h *MinHeap) Push(x interface{}) {
	h.elements = append(h.elements, x.(int64))
}

func (h *MinHeap) Pop() interface{} {
	old := h.elements
	n := len(old)
	h.elements = old[0 : n-1]
	return old[n-1]
}

func solve(n int64, edges [][]int64, k int64) int64 {
	// Build the graph
	graph := make(map[int64][][2]int64)
	for _, edge := range edges {
		u, v, w := edge[0], edge[1], edge[2]
		graph[u] = append(graph[u], [2]int64{v, w})
		graph[v] = append(graph[v], [2]int64{u, w})
	}

	// Initialize the min-heap with each node as its own component
	heap := &MinHeap{}
	for i := int64(0); i < n; i++ {
		heap.Push(0)
	}

	// Union-Find data structure
	parent := make([]int64, n)
	rank := make([]int64, n)
	for i := int64(0); i < n; i++ {
		parent[i] = i
		rank[i] = 1
	}

	// Find function with path compression
	find := func(u int64) int64 {
		if parent[u] != u {
			parent[u] = find(parent[u])
		}
		return parent[u]
	}

	// Union function with union by rank
	union := func(u, v int64) bool {
		uRoot := find(u)
		vRoot := find(v)
		if uRoot == vRoot {
			return false
		}
		if rank[uRoot] < rank[vRoot] {
			parent[uRoot] = vRoot
			rank[vRoot] += rank[uRoot]
		} else {
			parent[vRoot] = uRoot
			rank[uRoot] += rank[vRoot]
		}
		return true
	}

	// Sort edges by weight in ascending order
	sort.Slice(edges, func(i, j int) bool {
		return edges[i][2] < edges[j][2]
	})

	// Process edges in order of increasing weight
	for _, edge := range edges {
		u, v, w := edge[0], edge[1], edge[2]
		if find(u) != find(v) {
			union(u, v)
			// Get the sizes of the two components
			sizeU := rank[find(u)]
			sizeV := rank[find(v)]
			newSize := sizeU + sizeV
			// Get the max weight of the two components
			maxWeight := max(heap.Peek(), w)
			// Remove the old max weight and push the new one
			heap.Pop()
			heap.Push(maxWeight)
		}
	}

	// Find the maximum of the first k elements in the heap
	result := int64(0)
	count := int64(0)
	for heap.Len() > 0 && count < k {
		result = max(result, heap.Peek())
		heap.Pop()
		count++
	}

	return result
}

func max(a, b int64) int64 {
	if a > b {
		return a
	}
	return b
}

func (h *MinHeap) Peek() int64 {
	return h.elements[0]
}
